  };

  function cloneProducts() {
    return INITIAL_PRODUCTS.map((p) => ({ ...p }));
  }

  function defaultState() {
    const today = new Date().toISOString().slice(0, 10);
    return {
      orderSeq: 1002,
      products: cloneProducts(),
      orders: [
        {
          id_order: 1001,
          client_name: "Client Demo",
          client_login: "client",
          date_created: today,
          date_delivery: today,
          status: "accepted",
