            { name: "Tomatoes, round, salad vine", quantity: 80, unit: "kg", price_fixed: 2.15, line_total: 172 },
            { name: "Carrots, washed, bulk", quantity: 45, unit: "kg", price_fixed: 0.95, line_total: 42.75 },
          ],
        },
      ],
    };
  }

  function loadState() {
    try {
      const raw = sessionStorage.getItem(STORAGE_KEY);
      if (!raw) return defaultState();
      return JSON.parse(raw);
    } catch (error) {
      return defaultState();
    }
  }

  function saveState(state) {
    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  let state = loadState();

  function findProduct(id) {
    return state.products.find((p) => Number(p.id_product) === Number(id));
  }

  function lineTotal(lines) {
    let total = 0;
    lines.forEach((line) => {
      const p = findProduct(line.id_product);
      if (p) total += Number(line.quantity) * Number(p.price);
    });
    return Math.round(total * 100) / 100;
  }

  function resolveAuth(token) {
    if (!token) return null;
    return AUTH_BY_TOKEN[token] || null;
  }

  function requireAuth(token, role) {
    const auth = resolveAuth(token);
    if (!auth) {
      const err = new Error("Unauthorized");
      err.status = 401;
      throw err;
    }
    if (role && auth.role !== role) {
      const err = new Error("Forbidden");
      err.status = 403;
      throw err;
    }
    return auth;
  }

  window.MockStore = {
    handle(method, path, body, token) {
      if (method === "POST" && path === "/api/logout") {
        return { ok: true };
      }

      if (method === "GET" && path === "/api/products") {
        requireAuth(token);
        const sorted = [...state.products].sort(
          (a, b) => -Number(a.freq) + Number(b.freq) || a.name.localeCompare(b.name)
        );
        return sorted;
      }

      if (method === "GET" && path === "/api/orders") {
        const auth = requireAuth(token);
        return state.orders
          .filter((o) => auth.role === "manager" || o.client_login === auth.login)
          .map((o) => ({
            id_order: o.id_order,
            date_created: o.date_created,
            date_delivery: o.date_delivery,
            status: o.status,
            total: o.total,
          }));
      }

      const orderMatch = path.match(/^\/api\/orders\/(\d+)$/);
      if (method === "GET" && orderMatch) {
        const auth = requireAuth(token);
        const id = Number(orderMatch[1]);
        const order = state.orders.find((o) => Number(o.id_order) === id);
        if (!order) {
          const err = new Error("Order not found");
          err.status = 404;
          throw err;
        }
        if (auth.role !== "manager" && order.client_login !== auth.login) {
          const err = new Error("Forbidden");
          err.status = 403;
          throw err;
        }
        return order;
      }

      if (method === "POST" && path === "/api/orders") {
        const auth = requireAuth(token, "client");
        const lines = body?.lines || [];
        const dateDelivery = body?.date_delivery;
        const comment = String(body?.comment || "").slice(0, 500);
        const deficitLines = [];

        lines.forEach((line) => {
          const pid = Number(line.id_product);
          const qty = Number(line.quantity);
          const p = findProduct(pid);
          if (!p) return;
          if (qty > Number(p.stock_qty)) {
            deficitLines.push({
              id_product: pid,
              name: p.name,
              requested: qty,
              available: p.stock_qty,
              alternatives: state.products
                .filter(
                  (alt) =>
                    alt.category === p.category &&
                    Number(alt.id_product) !== pid &&
                    Number(alt.stock_qty) > 0
                )
                .map((alt) => ({
                  id_product: alt.id_product,
                  name: alt.name,
                  stock_qty: alt.stock_qty,
                  price: alt.price,
                })),
            });
          }
        });

        if (deficitLines.length) {
          return { status: "deficit", deficit_lines: deficitLines };
        }

        lines.forEach((line) => {
          const p = findProduct(line.id_product);
          if (p) {
            p.stock_qty = Math.max(0, Math.round((Number(p.stock_qty) - Number(line.quantity)) * 100) / 100);
          }
        });

        state.orderSeq += 1;
        const now = new Date().toISOString().slice(0, 10);
        const fullLines = lines
          .map((line) => {
            const p = findProduct(line.id_product);
            if (!p) return null;
            const qty = Number(line.quantity);
            return {
              name: p.name,
              quantity: qty,
              unit: p.unit,
              price_fixed: p.price,
              line_total: Math.round(qty * Number(p.price) * 100) / 100,
            };
          })
          .filter(Boolean);

        const order = {
          id_order: state.orderSeq,
          client_name: auth.name,
          client_login: auth.login,
          date_created: now,
          date_delivery: dateDelivery,
          status: "confirmed",
          total: lineTotal(lines),
          comment,
          lines: fullLines,
        };
        state.orders.push(order);
        saveState(state);
        return { status: "confirmed", id_order: state.orderSeq, date_delivery: dateDelivery };
      }

      if (method === "GET" && path === "/api/manager/orders") {
        requireAuth(token, "manager");
        return state.orders.map((o) => ({
          id_order: o.id_order,
          client_name: o.client_name,
          date_created: o.date_created,
          date_delivery: o.date_delivery,
          status: o.status,
          total: o.total,
        }));
      }

      const statusMatch = path.match(/^\/api\/manager\/orders\/(\d+)\/status$/);
      if (method === "PATCH" && statusMatch) {
        requireAuth(token, "manager");
        const id = Number(statusMatch[1]);
        const status = body?.status;
        if (!["confirmed", "dispatched"].includes(status)) {
          const err = new Error("Unsupported status");
          err.status = 400;
          throw err;
        }
        const order = state.orders.find((o) => Number(o.id_order) === id);
        if (!order) {
          const err = new Error("Order not found");
          err.status = 404;
          throw err;
        }
        order.status = status;
        saveState(state);
        return { ok: true, status };
      }

      const err = new Error("Not found");
      err.status = 404;
      throw err;
    },
  };
})();

(function initOrderForm() {
  const productListEl = document.getElementById("productList");
  const frequentListEl = document.getElementById("frequentList");
  const cartItemsEl = document.getElementById("cartItems");
  const cartTotalEl = document.getElementById("cartTotal");
  const orderForm = document.getElementById("orderForm");
  const clearBtn = document.getElementById("clearBtn");
  const orderMessage = document.getElementById("orderMessage");
  const deliveryDateInput = document.getElementById("deliveryDate");
  const commentInput = document.getElementById("comment");
  const deficitModal = document.getElementById("deficitModal");
  const deficitBody = document.getElementById("deficitBody");
  const resubmitBtn = document.getElementById("resubmitBtn");
  const cancelDeficitBtn = document.getElementById("cancelDeficitBtn");

  let products = [];
  const productsById = new Map();
  const quantities = new Map();
  let pendingDeficit = null;

  function tomorrowDateISO() {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    return d.toISOString().slice(0, 10);
  }

  function showMessage(type, text) {
    orderMessage.className = `message message--${type}`;
    orderMessage.textContent = text;
    orderMessage.style.display = "block";
  }

  function clearMessage() {
    orderMessage.style.display = "none";
    orderMessage.textContent = "";
    orderMessage.className = "";
  }

  function getQuantity(idProduct) {
    return Number(quantities.get(idProduct) || 0);
  }

  function setQuantity(idProduct, value) {
    quantities.set(idProduct, Number(value) || 0);
  }

  function renderProductRow(product, isFrequent) {
    const row = document.createElement("div");
    row.className = `product-row ${isFrequent ? "product-row--freq" : ""} ${product.stock_qty <= 0 ? "product-row--disabled" : ""}`.trim();

    const qty = getQuantity(product.id_product);
    const isTooMuch = qty > Number(product.stock_qty);
    const qtyHint = isTooMuch ? `<div class="hint-error">Only ${Number(product.stock_qty).toFixed(2)} available</div>` : "";

    row.innerHTML = `
      <div><strong>${product.name}</strong></div>
      <div>${product.category || "-"}</div>
      <div>${product.unit}</div>
      <div>${Number(product.stock_qty).toFixed(2)}</div>
      <div>${formatMoney(product.price)}</div>
      <div>
        <input
          class="qty-input ${isTooMuch ? "invalid" : ""}"
          data-product-id="${product.id_product}"
          type="number"
          min="0"
          step="0.01"
          value="${qty > 0 ? qty : ""}"
          ${product.stock_qty <= 0 ? "disabled" : ""}
          title="${isTooMuch ? `Only ${Number(product.stock_qty).toFixed(2)} available` : ""}"
        >
        ${qtyHint}
      </div>
    `;
    return row;
  }

  function renderProducts() {
    const frequent = products.filter((p) => Number(p.freq) > 0).slice(0, 5);
    const nonFrequent = products.filter((p) => !frequent.some((f) => f.id_product === p.id_product));
    frequentListEl.innerHTML = "";
    productListEl.innerHTML = "";

    frequent.forEach((p) => frequentListEl.appendChild(renderProductRow(p, true)));
    nonFrequent.forEach((p) => productListEl.appendChild(renderProductRow(p, false)));
  }

  function cartLines() {
    return products
      .map((product) => ({
        product,
        quantity: getQuantity(product.id_product)
      }))
      .filter((item) => item.quantity > 0);
  }

  function renderCart() {
    const lines = cartLines();
    if (!lines.length) {
      cartItemsEl.innerHTML = `<div class="cart-row"><div>Cart is empty</div><div></div><div></div><div></div></div>`;
      cartTotalEl.textContent = "0.00 BYN";
      return;
    }

    let total = 0;
    cartItemsEl.innerHTML = lines.map(({ product, quantity }) => {
      const lineTotal = Number(quantity) * Number(product.price);
      total += lineTotal;
      return `
        <div class="cart-row">
          <div>${product.name}</div>
          <div>${Number(quantity).toFixed(2)}</div>
          <div>${product.unit}</div>
          <div>${formatMoney(lineTotal)}</div>
        </div>
      `;
    }).join("");

    cartTotalEl.textContent = formatMoney(total);
  }

  function syncAllQtyInputs() {
    document.querySelectorAll(".qty-input").forEach((input) => {
      const id = Number(input.dataset.productId);
      const product = productsById.get(id);
      const qty = getQuantity(id);
      const tooMuch = qty > Number(product.stock_qty);
      input.value = qty > 0 ? qty : "";
      input.classList.toggle("invalid", tooMuch);
      input.title = tooMuch ? `Only ${Number(product.stock_qty).toFixed(2)} available` : "";
      const hint = input.parentElement.querySelector(".hint-error");
      if (tooMuch && !hint) {
        const h = document.createElement("div");
        h.className = "hint-error";
        h.textContent = `Only ${Number(product.stock_qty).toFixed(2)} available`;
        input.parentElement.appendChild(h);
      }
      if (!tooMuch && hint) {
        hint.remove();
      }
    });
  }

  function hasStockErrors() {
    return cartLines().some(({ product, quantity }) => Number(quantity) > Number(product.stock_qty));
  }

  function getOrderPayload() {
    return {
      date_delivery: deliveryDateInput.value,
      comment: (commentInput.value || "").trim(),
      lines: cartLines().map(({ product, quantity }) => ({
        id_product: product.id_product,
        quantity: Number(quantity)
      }))
    };
  }

  async function submitOrder() {
    clearMessage();
    if (!deliveryDateInput.value) {
      showMessage("error", "Delivery date is required.");
      return;
    }

    const lines = cartLines();
    if (!lines.length) {
      showMessage("warning", "Cart is empty.");
      return;
    }

    if (hasStockErrors()) {
      showMessage("error", "Some quantities exceed stock.");
      return;
    }

    const response = await apiPost("/api/orders", getOrderPayload());

    if (response.status === "confirmed") {
      showMessage("success", `Order #${response.id_order} confirmed for ${response.date_delivery}.`);
      clearQuantities();
      renderCart();
      syncAllQtyInputs();
      return;
    }

    if (response.status === "deficit") {
      openDeficitModal(response.deficit_lines || []);
      return;
    }
  }

  function clearQuantities() {
    products.forEach((p) => setQuantity(p.id_product, 0));
  }

  function openDeficitModal(deficitLines) {
    pendingDeficit = deficitLines;
    deficitBody.innerHTML = "";

    deficitLines.forEach((line, idx) => {
      const tr = document.createElement("tr");
      const alternatives = line.alternatives || [];
      tr.innerHTML = `
        <td>${line.name}</td>
        <td>${Number(line.requested).toFixed(2)}</td>
        <td>${Number(line.available).toFixed(2)}</td>
        <td>
          <select data-deficit-index="${idx}">
            <option value="remove">Remove this line</option>
            ${alternatives.map((alt) => `<option value="${alt.id_product}">${alt.name} (${Number(alt.stock_qty).toFixed(2)} ${productsById.get(alt.id_product)?.unit || ""})</option>`).join("")}
          </select>
        </td>
      `;
      deficitBody.appendChild(tr);
    });

    deficitModal.classList.add("active");
    deficitModal.setAttribute("aria-hidden", "false");
  }

  function closeDeficitModal() {
    deficitModal.classList.remove("active");
    deficitModal.setAttribute("aria-hidden", "true");
  }

  function applyDeficitChoices() {
    // Reset items that were in deficit before applying chosen replacements.
    pendingDeficit.forEach((line) => setQuantity(line.id_product, 0));

    const selectors = deficitBody.querySelectorAll("select[data-deficit-index]");
    selectors.forEach((selectEl) => {
      const idx = Number(selectEl.dataset.deficitIndex);
      const line = pendingDeficit[idx];
      const choice = selectEl.value;
      if (!line) return;

      if (choice !== "remove") {
        const altId = Number(choice);
        const alt = (line.alternatives || []).find((a) => Number(a.id_product) === altId);
        if (alt) {
          // Keep requested quantity, capped by alternative stock to avoid immediate repeat deficit.
          const qty = Math.min(Number(line.requested), Number(alt.stock_qty));
          setQuantity(altId, qty);
        }
      }
    });
  }

  async function loadProducts() {
    products = await apiGet("/api/products");
    productsById.clear();
    products.forEach((p) => {
      productsById.set(Number(p.id_product), p);
      if (!quantities.has(Number(p.id_product))) {
        setQuantity(Number(p.id_product), 0);
      }
    });
    renderProducts();
    renderCart();
  }

  document.addEventListener("input", (event) => {
    const target = event.target;
    if (!target.classList.contains("qty-input")) return;

    const id = Number(target.dataset.productId);
    const nextValue = Number(target.value || 0);
    setQuantity(id, nextValue);
    syncAllQtyInputs();
    renderCart();
  });

  orderForm.addEventListener("submit", (event) => {
    event.preventDefault();
    submitOrder().catch((error) => {
      showMessage("error", error.message || "Failed to submit order.");
    });
  });

  clearBtn.addEventListener("click", () => {
    clearQuantities();
    commentInput.value = "";
    clearMessage();
    renderCart();
    syncAllQtyInputs();
  });

  cancelDeficitBtn.addEventListener("click", () => {
    closeDeficitModal();
    clearQuantities();
    commentInput.value = "";
    renderCart();
    syncAllQtyInputs();
  });

  resubmitBtn.addEventListener("click", () => {
    if (!pendingDeficit) return;
    applyDeficitChoices();
    closeDeficitModal();
    renderCart();
    syncAllQtyInputs();
    submitOrder().catch((error) => {
      showMessage("error", error.message || "Failed to resubmit order.");
    });
  });

  deliveryDateInput.min = tomorrowDateISO();

  loadProducts().catch((error) => {
    showMessage("error", "Failed to load products.");
    productListEl.innerHTML = "";
    frequentListEl.innerHTML = "";
  });
})();

(function initOrderHistory() {
  const body = document.getElementById("ordersBody");
  const expandedRows = new Set();

  function statusBadge(status) {
    const klass = `badge badge-${status || ""}`;
    return `<span class="${klass}">${status || ""}</span>`;
  }

  function renderLinesRow(orderId, lines) {
    const tr = document.createElement("tr");
    tr.dataset.detailsFor = orderId;
    const td = document.createElement("td");
    td.colSpan = 5;
    td.innerHTML = lines.length
      ? `<div class="table-wrap"><table>
          <thead><tr><th>Name</th><th>Qty</th><th>Unit</th><th>Price</th><th>Line total</th></tr></thead>
          <tbody>${lines.map((line) => `
            <tr>
              <td>${line.name}</td>
              <td>${Number(line.quantity).toFixed(2)}</td>
              <td>${line.unit}</td>
              <td>${formatMoney(line.price_fixed)}</td>
              <td>${formatMoney(line.line_total)}</td>
            </tr>
          `).join("")}</tbody>
        </table></div>`
      : "No lines";
    tr.appendChild(td);
    return tr;
  }

  async function toggleDetails(orderId, hostRow) {
    if (expandedRows.has(orderId)) {
      const details = body.querySelector(`tr[data-details-for="${orderId}"]`);
      if (details) details.remove();
      expandedRows.delete(orderId);
      return;
    }

    const order = await apiGet(`/api/orders/${orderId}`);
    const detailsRow = renderLinesRow(orderId, order.lines || []);
    hostRow.insertAdjacentElement("afterend", detailsRow);
    expandedRows.add(orderId);
  }

  async function loadOrders() {
    const orders = await apiGet("/api/orders");
    body.innerHTML = "";

    orders.forEach((order) => {
      const tr = document.createElement("tr");
      tr.innerHTML = `
        <td>${order.id_order}</td>
        <td>${order.date_created}</td>
        <td>${order.date_delivery}</td>
        <td>${statusBadge(order.status)}</td>
        <td>${formatMoney(order.total)}</td>
      `;
      tr.addEventListener("click", () => {
        toggleDetails(order.id_order, tr).catch(() => {
          alert("Cannot load order details.");
        });
      });
      body.appendChild(tr);
    });
  }

  loadOrders().catch(() => {
    body.innerHTML = `<tr><td colspan="5">Failed to load orders.</td></tr>`;
  });
})();

(function initManagerDashboard() {
  const body = document.getElementById("managerOrdersBody");
  const statusFilterEl = document.getElementById("statusFilter");
  const fromDateEl = document.getElementById("fromDate");
  const toDateEl = document.getElementById("toDate");

  let allOrders = [];

  function statusBadge(status) {
    return `<span class="badge badge-${status}">${status}</span>`;
  }

  function inDateRange(orderDate, fromDate, toDate) {
    if (fromDate && orderDate < fromDate) return false;
    if (toDate && orderDate > toDate) return false;
    return true;
  }

  function filteredOrders() {
    const wantedStatus = statusFilterEl.value;
    const fromDate = fromDateEl.value;
    const toDate = toDateEl.value;

    return allOrders.filter((order) => {
      const statusOk = wantedStatus === "all" || order.status === wantedStatus;
      const dateOk = inDateRange(order.date_created, fromDate, toDate);
      return statusOk && dateOk;
    });
  }

  function renderRows() {
    const rows = filteredOrders();
    body.innerHTML = rows.map((order) => `
      <tr data-order-id="${order.id_order}">
        <td>${order.id_order}</td>
        <td>${order.client_name}</td>
        <td>${order.date_created}</td>
        <td>${order.date_delivery}</td>
        <td>${statusBadge(order.status)}</td>
        <td>${formatMoney(order.total)}</td>
        <td>
          <div class="row">
            <select class="status-select">
              <option value="confirmed" ${order.status === "confirmed" ? "selected" : ""}>confirmed</option>
              <option value="dispatched" ${order.status === "dispatched" ? "selected" : ""}>dispatched</option>
            </select>
            <button class="btn btn-secondary save-status-btn" type="button">Save</button>
          </div>
        </td>
      </tr>
    `).join("");
  }

  async function saveStatus(orderId, status) {
    await apiPatch(`/api/manager/orders/${orderId}/status`, { status });
    allOrders = allOrders.map((order) => (
      Number(order.id_order) === Number(orderId) ? { ...order, status } : order
    ));
    renderRows();
  }

  async function loadOrders() {
    allOrders = await apiGet("/api/manager/orders");
    renderRows();
  }

  [statusFilterEl, fromDateEl, toDateEl].forEach((el) => {
    el.addEventListener("input", renderRows);
  });

  body.addEventListener("click", (event) => {
    const btn = event.target.closest(".save-status-btn");
    if (!btn) return;
    const row = btn.closest("tr");
    const select = row.querySelector(".status-select");
    const idOrder = row.dataset.orderId;
    saveStatus(idOrder, select.value).catch((error) => {
      alert(error.message || "Failed to update status.");
    });
  });

  loadOrders().catch(() => {
    body.innerHTML = `<tr><td colspan="7">Failed to load manager orders.</td></tr>`;
  });
})();
